<svg viewBox="0 0 700 480" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="32" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Zeitleiste der Restrukturierung der Ethereum Foundation — 2026</text>
  <g font-family="sans-serif">
    <line x1="60" y1="70" x2="60" y2="420" stroke="#3f3f46" stroke-width="2"/>
